6250 Value *llvm::isBytewiseValue(Value *V, const DataLayout &DL) {
6251 
6252   // All byte-wide stores are splatable, even of arbitrary variables.
6253   if (V->getType()->isIntegerTy(8))
6254     return V;
6255 
6256   LLVMContext &Ctx = V->getContext();
6257 
6258   // Undef don't care.
6259   auto *UndefInt8 = UndefValue::get(Type::getInt8Ty(Ctx));
6260   if (isa<UndefValue>(V))
6261     return UndefInt8;
6262 
6263   // Return poison for zero-sized type.
6264   if (DL.getTypeStoreSize(V->getType()).isZero())
6265     return PoisonValue::get(Type::getInt8Ty(Ctx));
6266 
6267   Constant *C = dyn_cast<Constant>(V);
6268   if (!C) {
6269     // Conceptually, we could handle things like:
6270     //   %a = zext i8 %X to i16
6271     //   %b = shl i16 %a, 8
6272     //   %c = or i16 %a, %b
6273     // but until there is an example that actually needs this, it doesn't seem
6274     // worth worrying about.
6275     return nullptr;
6276   }
6277 
6278   // Handle 'null' ConstantArrayZero etc.
6279   if (C->isNullValue())
6280     return Constant::getNullValue(Type::getInt8Ty(Ctx));
6281 
6282   // Constant floating-point values can be handled as integer values if the
6283   // corresponding integer value is "byteable".  An important case is 0.0.
6284   if (ConstantFP *CFP = dyn_cast<ConstantFP>(C)) {
6285     Type *ScalarTy = CFP->getType()->getScalarType();
6286     if (ScalarTy->isHalfTy() || ScalarTy->isFloatTy() || ScalarTy->isDoubleTy())
6287       return isBytewiseValue(
6288           ConstantInt::get(Ctx, CFP->getValue().bitcastToAPInt()), DL);
6289 
6290     // Don't handle long double formats, which have strange constraints.
6291     return nullptr;
6292   }
6293 
6294   // We can handle constant integers that are multiple of 8 bits.
6295   if (ConstantInt *CI = dyn_cast<ConstantInt>(C)) {
6296     if (CI->getBitWidth() % 8 == 0) {
6297       if (!CI->getValue().isSplat(8))
6298         return nullptr;
6299       return ConstantInt::get(Ctx, CI->getValue().trunc(8));
6300     }
6301   }
6302 
6303   if (auto *CE = dyn_cast<ConstantExpr>(C)) {
6304     if (CE->getOpcode() == Instruction::IntToPtr) {
6305       if (auto *PtrTy = dyn_cast<PointerType>(CE->getType())) {
6306         unsigned BitWidth = DL.getPointerSizeInBits(PtrTy->getAddressSpace());
6307         if (Constant *Op = ConstantFoldIntegerCast(
6308                 CE->getOperand(0), Type::getIntNTy(Ctx, BitWidth), false, DL))
6309           return isBytewiseValue(Op, DL);
6310       }
6311     }
6312   }
6313 
6314   auto Merge = [&](Value *LHS, Value *RHS) -> Value * {
6315     if (LHS == RHS)
6316       return LHS;
6317     if (!LHS || !RHS)
6318       return nullptr;
6319     if (LHS == UndefInt8)
6320       return RHS;
6321     if (RHS == UndefInt8)
6322       return LHS;
6323     return nullptr;
6324   };
6325 
6326   if (ConstantDataSequential *CA = dyn_cast<ConstantDataSequential>(C)) {
6327     Value *Val = UndefInt8;
6328     for (uint64_t I = 0, E = CA->getNumElements(); I != E; ++I)
6329       if (!(Val = Merge(Val, isBytewiseValue(CA->getElementAsConstant(I), DL))))
6330         return nullptr;
6331     return Val;
6332   }
6333 
6334   if (isa<ConstantAggregate>(C)) {
6335     Value *Val = UndefInt8;
6336     for (Value *Op : C->operands())
6337       if (!(Val = Merge(Val, isBytewiseValue(Op, DL))))
6338         return nullptr;
6339     return Val;
6340   }
6341 
6342   // Don't try to handle the handful of other constants.
6343   return nullptr;
6344 }
