 842 /// Takes a memcpy and a call that it depends on,
 843 /// and checks for the possibility of a call slot optimization by having
 844 /// the call write its result directly into the destination of the memcpy.
 845 bool MemCpyOptPass::performCallSlotOptzn(Instruction *cpyLoad,
 846                                          Instruction *cpyStore, Value *cpyDest,
 847                                          Value *cpySrc, TypeSize cpySize,
 848                                          Align cpyDestAlign,
 849                                          BatchAAResults &BAA,
 850                                          std::function<CallInst *()> GetC) {
 851   // The general transformation to keep in mind is
 852   //
 853   //   call @func(..., src, ...)
 854   //   memcpy(dest, src, ...)
 855   //
 856   // ->
 857   //
 858   //   memcpy(dest, src, ...)
 859   //   call @func(..., dest, ...)
 860   //
 861   // Since moving the memcpy is technically awkward, we additionally check that
 862   // src only holds uninitialized values at the moment of the call, meaning that
 863   // the memcpy can be discarded rather than moved.
 864 
 865   // We can't optimize scalable types.
 866   if (cpySize.isScalable())
 867     return false;
 868 
 869   // Require that src be an alloca.  This simplifies the reasoning considerably.
 870   auto *srcAlloca = dyn_cast<AllocaInst>(cpySrc);
 871   if (!srcAlloca)
 872     return false;
 873 
 874   const DataLayout &DL = cpyLoad->getDataLayout();
 875   // We can't optimize scalable types or variable-length allocas.
 876   std::optional<TypeSize> SrcAllocaSize = srcAlloca->getAllocationSize(DL);
 877   if (!SrcAllocaSize || SrcAllocaSize->isScalable())
 878     return false;
 879   uint64_t srcSize = SrcAllocaSize->getFixedValue();
 880 
 881   if (cpySize < srcSize)
 882     return false;
 883 
 884   CallInst *C = GetC();
 885   if (!C)
 886     return false;
 887 
 888   // Lifetime marks shouldn't be operated on.
 889   if (Function *F = C->getCalledFunction())
 890     if (F->isIntrinsic() && F->getIntrinsicID() == Intrinsic::lifetime_start)
 891       return false;
 892 
 893   if (C->getParent() != cpyStore->getParent()) {
 894     LLVM_DEBUG(dbgs() << "Call Slot: block local restriction\n");
 895     return false;
 896   }
 897 
 898   MemoryLocation DestLoc =
 899       isa<StoreInst>(cpyStore)
 900           ? MemoryLocation::get(cpyStore)
 901           : MemoryLocation::getForDest(cast<MemCpyInst>(cpyStore));
 902 
 903   // Check that nothing touches the dest of the copy between
 904   // the call and the store/memcpy.
 905   Instruction *SkippedLifetimeStart = nullptr;
 906   if (accessedBetween(BAA, DestLoc, MSSA->getMemoryAccess(C),
 907                       MSSA->getMemoryAccess(cpyStore), &SkippedLifetimeStart)) {
 908     LLVM_DEBUG(dbgs() << "Call Slot: Dest pointer modified after call\n");
 909     return false;
 910   }
 911 
 912   // If we need to move a lifetime.start above the call, make sure that we can
 913   // actually do so. If the argument is bitcasted for example, we would have to
 914   // move the bitcast as well, which we don't handle.
 915   if (SkippedLifetimeStart) {
 916     auto *LifetimeArg =
 917         dyn_cast<Instruction>(SkippedLifetimeStart->getOperand(0));
 918     if (LifetimeArg && LifetimeArg->getParent() == C->getParent() &&
 919         C->comesBefore(LifetimeArg))
 920       return false;
 921   }
 922 
 923   // Check that storing to the first srcSize bytes of dest will not cause a
 924   // trap or data race.
 925   bool ExplicitlyDereferenceableOnly;
 926   if (!isWritableObject(getUnderlyingObject(cpyDest),
 927                         ExplicitlyDereferenceableOnly) ||
 928       !isDereferenceableAndAlignedPointer(cpyDest, Align(1), APInt(64, cpySize),
 929                                           DL, C, AC, DT)) {
 930     LLVM_DEBUG(dbgs() << "Call Slot: Dest pointer not dereferenceable\n");
 931     return false;
 932   }
 933 
 934   // Make sure that nothing can observe cpyDest being written early. There are
 935   // a number of cases to consider:
 936   //  1. cpyDest cannot be accessed between C and cpyStore as a precondition of
 937   //     the transform.
 938   //  2. C itself may not access cpyDest (prior to the transform). This is
 939   //     checked further below.
 940   //  3. If cpyDest is accessible to the caller of this function (potentially
 941   //     captured and not based on an alloca), we need to ensure that we cannot
 942   //     unwind between C and cpyStore. This is checked here.
 943   //  4. If cpyDest is potentially captured, there may be accesses to it from
 944   //     another thread. In this case, we need to check that cpyStore is
 945   //     guaranteed to be executed if C is. As it is a non-atomic access, it
 946   //     renders accesses from other threads undefined.
 947   //     TODO: This is currently not checked.
 948   if (mayBeVisibleThroughUnwinding(cpyDest, C, cpyStore)) {
 949     LLVM_DEBUG(dbgs() << "Call Slot: Dest may be visible through unwinding\n");
 950     return false;
 951   }
 952 
 953   // Check that dest points to memory that is at least as aligned as src.
 954   Align srcAlign = srcAlloca->getAlign();
 955   bool isDestSufficientlyAligned = srcAlign <= cpyDestAlign;
 956   // If dest is not aligned enough and we can't increase its alignment then
 957   // bail out.
 958   if (!isDestSufficientlyAligned && !isa<AllocaInst>(cpyDest)) {
 959     LLVM_DEBUG(dbgs() << "Call Slot: Dest not sufficiently aligned\n");
 960     return false;
 961   }
 962 
 963   // Check that src is not accessed except via the call and the memcpy.  This
 964   // guarantees that it holds only undefined values when passed in (so the final
 965   // memcpy can be dropped), that it is not read or written between the call and
 966   // the memcpy, and that writing beyond the end of it is undefined.
 967   SmallVector<User *, 8> srcUseList(srcAlloca->users());
 968   while (!srcUseList.empty()) {
 969     User *U = srcUseList.pop_back_val();
 970 
 971     if (isa<AddrSpaceCastInst>(U)) {
 972       append_range(srcUseList, U->users());
 973       continue;
 974     }
 975     if (isa<LifetimeIntrinsic>(U))
 976       continue;
