 978     if (U != C && U != cpyLoad) {
 979       LLVM_DEBUG(dbgs() << "Call slot: Source accessed by " << *U << "\n");
 980       return false;
 981     }
 982   }
 983 
 984   // Check whether src is captured by the called function, in which case there
 985   // may be further indirect uses of src.
 986   bool SrcIsCaptured = any_of(C->args(), [&](Use &U) {
 987     return U->stripPointerCasts() == cpySrc &&
 988            !C->doesNotCapture(C->getArgOperandNo(&U));
 989   });
 990 
 991   // If src is captured, then check whether there are any potential uses of
 992   // src through the captured pointer before the lifetime of src ends, either
 993   // due to a lifetime.end or a return from the function.
 994   if (SrcIsCaptured) {
 995     // Check that dest is not captured before/at the call. We have already
 996     // checked that src is not captured before it. If either had been captured,
 997     // then the call might be comparing the argument against the captured dest
 998     // or src pointer.
 999     Value *DestObj = getUnderlyingObject(cpyDest);
1000     if (!isIdentifiedFunctionLocal(DestObj) ||
1001         PointerMayBeCapturedBefore(DestObj, /* ReturnCaptures */ true, C, DT,
1002                                    /* IncludeI */ true))
1003       return false;
1004 
1005     MemoryLocation SrcLoc =
1006         MemoryLocation(srcAlloca, LocationSize::precise(srcSize));
1007     for (Instruction &I :
1008          make_range(++C->getIterator(), C->getParent()->end())) {
1009       // Lifetime of srcAlloca ends at lifetime.end.
1010       if (auto *II = dyn_cast<IntrinsicInst>(&I)) {
1011         if (II->getIntrinsicID() == Intrinsic::lifetime_end &&
1012             II->getArgOperand(0) == srcAlloca)
1013           break;
1014       }
1015 
1016       // Lifetime of srcAlloca ends at return.
1017       if (isa<ReturnInst>(&I))
1018         break;
1019 
1020       // Ignore the direct read of src in the load.
1021       if (&I == cpyLoad)
1022         continue;
1023 
1024       // Check whether this instruction may mod/ref src through the captured
1025       // pointer (we have already any direct mod/refs in the loop above).
1026       // Also bail if we hit a terminator, as we don't want to scan into other
1027       // blocks.
1028       if (isModOrRefSet(BAA.getModRefInfo(&I, SrcLoc)) || I.isTerminator())
1029         return false;
